// // This module decrements the 4-bit counter on every rising edge of the clock when the enable signal is low.
module binary_counter(
	input clk,
	input rst,
	input en,
	output reg [3:0] count
);

	always @(posedge clk) begin
		if (rst) begin
			count <= 4'b0000;
		end
		else if (en) begin
			count <= count + 1'b1;
		end
	end

endmodule
